class Solution {
public:
    int longestPalindrome(string s, string t) {
        string combined = s + "#" + t;
        int n = combined.size();
        vector<vector<int>> dp(n, vector<int>(n, 0));
        int maxLength = 0;

        for (int i = n - 1; i >= 0; --i) {
            dp[i][i] = 1;
            maxLength = 1;
            for (int j = i + 1; j < n; ++j) {
                if (combined[i] == combined[j]) {
                    dp[i][j] = (i + 1 <= j - 1 ? dp[i + 1][j - 1] : 0) + 2;
                    if (i < s.size() && j >= s.size() + 1) {
                        maxLength = max(maxLength, dp[i][j]);
                    }
                } else {
                    dp[i][j] = 0;
                }
            }
        }
        return maxLength;
    }
};
